property.code:
@blueStatus: #0747A6;
@greenStatus: #129a55;
@greyStatus: #42526E;
@purpleStatus: #392B84;
@redStatus: #B32503;
@yellowStatus: #997b00;
@whiteColor: #ffffff;
@lightenRatio: 60%;

.blueStatus.subtle {
  color: @blueStatus;
  background-color: lighten(@blueStatus, @lightenRatio);
}
.blueStatus {
  color: @whiteColor;
  background-color: @blueStatus;
}
.greenStatus.subtle {
  color: @greenStatus;
  background-color: lighten(@greenStatus, @lightenRatio);
}
.greenStatus {
  color: @whiteColor;
  background-color: @greenStatus;
}
.greyStatus.subtle {
  color: @greyStatus;
  background-color: lighten(@greyStatus, @lightenRatio);
}
.greyStatus {
  color: @whiteColor;
  background-color: @greyStatus;
}
.purpleStatus.subtle {
  color: @purpleStatus;
  background-color: lighten(@purpleStatus, @lightenRatio);
}
.purpleStatus {
  color: @whiteColor;
  background-color: @purpleStatus;
}
.redStatus.subtle {
  color: @redStatus;
  background-color: lighten(@redStatus, @lightenRatio);
}
.redStatus {
  color: @whiteColor;
  background-color: @redStatus;
}
.yellowStatus.subtle {
  color: @yellowStatus;
  background-color: lighten(@yellowStatus, @lightenRatio);
}
.yellowStatus {
  color: @whiteColor;
  background-color: @yellowStatus;
}
.statusBox {
  border-radius: 4px;
  padding: 4px;
  text-transform: uppercase;
  font-size: 10px;
  font-weight: bold;
  height: 19px;
}
